SELECT AVG(temperature) AS average_temperature
FROM weather_data
WHERE date = '2023-01-01' AND hour = 1;

SELECT *
FROM hourly_load
ORDER BY hour_end DESC;

SELECT hour_end, ercot
FROM hourly_load
WHERE ercot > (SELECT AVG(ercot) FROM hourly_load);

SELECT COUNT(*) AS total_rows
FROM forecast_loads
WHERE created_at LIKE '2023-%';

SELECT 
  (SELECT ercot FROM monthly_load WHERE year = 2013 AND month = 2) AS total_mwh_ercot,
  (SELECT coast FROM forecast_loads WHERE forecast_date = '2023-01-01' AND forecast_hour = 1) AS predicted_coast_load;
